{# Single-call context for signers + reusable values; defined once so every signature block / attachment loop can read from it. #}
{% set ctx = get_payment_voucher_context(doc.name) %}
{% set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "AED" %}
{% set is_internal_transfer = doc.payment_type == "Internal Transfer" %}
{% set is_tr_lc = doc.is_tr_lc_payment %}
{% set party_name = doc.party_name or doc.party or "" %}
{% set party_label = doc.party_type or "Party" %}
{% set party_address = doc.address_display or "" %}
{% set supplier_bank = {} %}
{% set supplier_swift = "" %}
{% if not is_internal_transfer and doc.party and doc.party_type %}
    {% set supplier_bank = frappe.db.get_value("Bank Account", {"party_type": doc.party_type, "party": doc.party, "is_default": 1}, ["name", "bank", "bank_account_no", "iban", "branch_code"], as_dict=True) or {} %}
    {% if supplier_bank and supplier_bank.bank %}
        {% set supplier_swift = frappe.db.get_value("Bank", supplier_bank.bank, "swift_number") or "" %}
    {% endif %}
{% endif %}
{% set issued_bank_details = frappe.db.get_value("Bank Account", doc.issued_bank, ["bank", "bank_account_no", "iban"], as_dict=True) or {} %}
{% set issued_bank_currency = doc.issued_currency or company_currency %}
{% set receiving_bank_details = {} %}
{% set receiving_bank_currency = doc.receiving_currency or company_currency %}
{% if is_internal_transfer and doc.receiving_bank %}
    {% set receiving_bank_details = frappe.db.get_value("Bank Account", doc.receiving_bank, ["bank", "bank_account_no", "iban"], as_dict=True) or {} %}
{% endif %}

<style>
@page { size: A4; margin: 12mm 15mm; }
body, .print-format { font-family: 'Segoe UI', Arial, Helvetica, sans-serif; font-size: 11pt; color: #1a1a1a; line-height: 1.4; }
table { border-collapse: collapse; width: 100%; }
.title { text-align: center; font-size: 15pt; font-weight: 700; border: 2px solid #000; padding: 10px 8px; margin: 12px 0; letter-spacing: 0.5px; }
.header-blue { background-color: #c9daf8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 6px 10px; border: 1px solid #000; font-size: 10pt; }
.header-green { background-color: #d9ead3 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 6px 10px; border: 1px solid #000; font-size: 10pt; }
.header-red { background-color: #f4cccc !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 6px 10px; border: 1px solid #000; font-size: 10pt; }
.tbl td, .tbl th { border: 1px solid #000; padding: 5px 8px; vertical-align: top; font-size: 10pt; }
.tbl .lbl { width: 38%; background-color: #f5f5f5 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 500; color: #333; }
.tbl .val { width: 62%; }
.half { width: 50%; vertical-align: top; }
.sig td { border: 1px solid #000; padding: 45px 10px 10px 10px; text-align: center; font-size: 10pt; font-weight: 500; }
.yellow { background-color: #ffff00 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; padding: 2px 8px; font-weight: bold; }
.right { text-align: right; }
.center { text-align: center; }
.bold { font-weight: bold; }
.inv td, .inv th { border: 1px solid #000; padding: 4px 6px; font-size: 10pt; }
.inv th { background-color: #c9daf8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; text-align: center; font-size: 10pt; font-weight: 600; }
.total-row { background-color: #e8e8e8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: bold; }
.att-section { page-break-before: always; margin-top: 15px; }
.att-img { max-width: 100%; border: 1px solid #ccc; margin: 5px 0; }
</style>

<div class="print-format">

{% if is_internal_transfer %}
<!-- INTERNAL TRANSFER -->
<div class="title">INTERNAL TRANSFER VOUCHER</div>

<table class="tbl"><tr><td class="header-blue center">Company</td><td class="center bold">{{ doc.company }}</td></tr></table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">FROM (Issued Bank)</td></tr>
<tr><td class="lbl">Bank</td><td class="val">{{ issued_bank_details.bank or doc.issued_bank or "" }}</td></tr>
<tr><td class="lbl">Account</td><td class="val">{{ doc.account or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ doc.account_no or issued_bank_details.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ doc.issued_currency or issued_bank_currency }}</td></tr>
<tr><td class="lbl">Amount</td><td class="val bold">{{ frappe.utils.fmt_money(doc.issued_amount or 0, currency=doc.issued_currency or issued_bank_currency) }}</td></tr>
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">TO (Receiving Bank)</td></tr>
<tr><td class="lbl">Bank</td><td class="val">{{ receiving_bank_details.bank or doc.receiving_bank or "" }}</td></tr>
<tr><td class="lbl">Account</td><td class="val">{{ doc.receiving_account or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ doc.receving_account_no or receiving_bank_details.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ doc.receiving_currency or receiving_bank_currency }}</td></tr>
<tr><td class="lbl">Amount</td><td class="val bold">{{ frappe.utils.fmt_money(doc.receiving_amount or 0, currency=doc.receiving_currency or receiving_bank_currency) }}</td></tr>
</table>
</td>
</tr>
</table>

<table class="tbl" style="margin-top:10px;">
<tr><td class="lbl">Voucher No.</td><td class="val">{{ doc.name }}</td></tr>
<tr><td class="lbl">Date</td><td class="val">{{ frappe.utils.formatdate(doc.posting_date, "d-M-yyyy") }}</td></tr>
{% if doc.issued_currency != doc.receiving_currency %}
<tr><td class="lbl">Exchange Rate</td><td class="val">1 {{ doc.issued_currency }} = {{ doc.transfer_exchange_rate or 1 }} {{ doc.receiving_currency }}</td></tr>
{% endif %}
{% if doc.remarks %}
<tr><td class="lbl">Remarks</td><td class="val">{{ doc.remarks }}</td></tr>
{% endif %}
</table>

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>{{ ctx.prepared_by_name or "" }}</small></td><td>Authorised-By<br/><small>{{ (ctx.signers.get("Authorised") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>{{ (ctx.signers.get("Approved Level 1") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>

{% else %}
<!-- REGULAR PAYMENT VOUCHER -->
<div class="title">PAYMENT VOUCHER</div>

<table class="tbl"><tr><td class="header-blue center">Company</td><td class="center bold">{{ doc.company }}</td></tr></table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">ISSUED BANK DETAILS</td></tr>
<tr><td class="lbl">Issued Bank</td><td class="val">{{ issued_bank_details.bank or doc.issued_bank or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ issued_bank_details.bank_account_no or issued_bank_details.iban or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ issued_bank_currency }}</td></tr>
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">VOUCHER DETAILS</td></tr>
<tr><td class="lbl">Voucher No.</td><td class="val">{{ doc.name }}</td></tr>
<tr><td class="lbl">Date</td><td class="val">{{ frappe.utils.formatdate(doc.posting_date, "d-M-yyyy") }}</td></tr>
<tr><td class="lbl">Payment Mode</td><td class="val">{{ doc.payment_mode or "" }}</td></tr>
{% if doc.cheque_date %}<tr><td class="lbl">Cheque Date</td><td class="val">{{ frappe.utils.formatdate(doc.cheque_date, "d-M-yyyy") }}</td></tr>{% endif %}
</table>
</td>
</tr>
</table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">{{ party_label|upper }} DETAILS</td></tr>
<tr><td class="lbl">{{ party_label }} Name</td><td class="val">{{ party_name }}</td></tr>
<tr><td class="lbl">Address</td><td class="val">{{ party_address }}</td></tr>
{% if doc.telephone %}<tr><td class="lbl">Telephone</td><td class="val">{{ doc.telephone }}</td></tr>{% endif %}
{% if doc.email %}<tr><td class="lbl">E-Mail</td><td class="val">{{ doc.email }}</td></tr>{% endif %}
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">BANK DETAILS (for TT/TR)</td></tr>
<tr><td class="lbl">Bank Account No.</td><td class="val">{{ supplier_bank.bank_account_no or supplier_bank.iban or "" }}</td></tr>
<tr><td class="lbl">Bank Name</td><td class="val">{{ supplier_bank.bank or "" }}</td></tr>
<tr><td class="lbl">SWIFT Code</td><td class="val">{{ supplier_swift }}</td></tr>
</table>
</td>
</tr>
</table>

<table class="inv" style="margin-top:10px;">
<tr><th colspan="7" class="header-blue">INVOICE DETAILS</th></tr>
<tr><th style="width:30px;">SI</th><th style="width:120px;">Supplier Invoice No</th><th style="width:72px;">Date</th><th style="width:40px;">Ccy</th><th style="width:90px;">Amount (FC)</th><th style="width:90px;">Amount ({{ company_currency }})</th><th>Reference</th><th>Remarks</th></tr>
{% set total_base = {"value": 0} %}
{% set currency_totals = {} %}
{% for row in doc.payment_references %}
{% set amount_fc = row.outstanding_amount or row.grand_total or 0 %}
{% set amount_base = row.base_outstanding_amount or row.base_grand_total or 0 %}
{% set curr = row.currency or company_currency %}
{% if curr not in currency_totals %}{% set _ = currency_totals.update({curr: {"fc": 0}}) %}{% endif %}
{% set _ = currency_totals[curr].update({"fc": currency_totals[curr]["fc"] + amount_fc}) %}
{% set _ = total_base.update({"value": total_base["value"] + amount_base}) %}
<tr>
<td class="center">{{ loop.index }}</td>
<td>{{ row.bill_no or row.reference_name }}</td>
<td class="center">{{ frappe.utils.formatdate(row.invoice_date, "dd-MM-yy") if row.invoice_date else "" }}</td>
<td class="center">{{ curr }}</td>
<td class="right">{{ frappe.utils.fmt_money(amount_fc, currency=curr) }}</td>
<td class="right">{{ frappe.utils.fmt_money(amount_base, currency=company_currency) }}</td>
<td>{{ row.document_reference or "" }}</td>
<td>{{ row.remarks or "" }}</td>
</tr>
{% endfor %}
<tr class="total-row">
<td colspan="4" class="center"><strong>TOTAL</strong></td>
<td class="right">{% for curr, amounts in currency_totals.items() %}{{ frappe.utils.fmt_money(amounts["fc"], currency=curr) }}{% if not loop.last %}<br>{% endif %}{% endfor %}</td>
<td class="right">{{ frappe.utils.fmt_money(total_base["value"], currency=company_currency) }}</td>
<td></td>
<td></td>
</tr>
</table>

{% if doc.remarks %}
<table class="tbl" style="margin-top:10px;"><tr><td class="header-blue">REMARKS</td></tr><tr><td>{{ doc.remarks }}</td></tr></table>
{% endif %}

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>{{ ctx.prepared_by_name or "" }}</small></td><td>Authorised-By<br/><small>{{ (ctx.signers.get("Authorised") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>{{ (ctx.signers.get("Approved Level 1") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>

{% if is_tr_lc %}
<div class="page-break"></div>

<!-- TR/LC APPLICATION -->
<table style="margin-bottom:10px;"><tr>
<td style="font-weight:bold; font-size:12pt;">{{ doc.company|upper }}</td>
<td style="text-align:right;">Requesting Division: <span class="yellow">{{ doc.department or "" }}</span></td>
</tr></table>

<div class="title">APPLICATION FOR TRUST RECEIPT PAYMENT</div>

<table class="tbl">
<tr><td colspan="2" class="header-blue">BENEFICIARY DETAILS</td></tr>
<tr><td class="lbl">Name of Beneficiary</td><td class="val bold">{{ party_name }}</td></tr>
<tr><td class="lbl">Address of Beneficiary</td><td class="val">{{ party_address }}</td></tr>
<tr><td class="lbl">Beneficiary Email</td><td class="val">{{ doc.email or "" }}</td></tr>
<tr><td class="lbl">Beneficiary Bank Name</td><td class="val bold">{{ supplier_bank.bank or "" }}</td></tr>
<tr><td class="lbl">Beneficiary Account/IBAN</td><td class="val">{{ supplier_bank.iban or supplier_bank.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">SWIFT Code</td><td class="val">{{ supplier_swift }}</td></tr>
</table>

<table class="tbl" style="margin-top:10px;">
<tr><td colspan="2" class="header-blue">TRUST RECEIPT DETAILS</td></tr>
<tr><td class="lbl">TR Amount & Currency</td><td class="val right bold">{{ doc.currency or company_currency }} {% set total_amount = 0 %}{% for row in doc.payment_references %}{% set total_amount = total_amount + (row.outstanding_amount or row.grand_total or 0) %}{% endfor %}{{ "{:,.2f}".format(total_amount) }}</td></tr>
<tr><td class="lbl">Type of TR</td><td class="val bold">{{ doc.tr_type or "" }}</td></tr>
<tr><td class="lbl">Port of Loading</td><td class="val">{{ doc.port_of_loading or "" }}</td></tr>
<tr><td class="lbl">Port of Discharge</td><td class="val">{{ doc.port_of_discharge or "" }}</td></tr>
<tr><td class="lbl">COO of Goods</td><td class="val">{{ doc.coo_of_goods or "" }}</td></tr>
<tr><td class="lbl">Mode of Shipment</td><td class="val">{{ doc.mode_of_shipment or "" }}</td></tr>
<tr><td class="lbl">Description of Goods</td><td class="val">{{ doc.goods_description or "" }}</td></tr>
</table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-green">YES (Documents Available)</td></tr>
<tr><td>Proforma Invoice</td><td class="center" style="width:60px;">{{ "Yes" if doc.has_proforma_invoice else "No" }}</td></tr>
<tr><td>Purchase Order</td><td class="center">{{ "Yes" if doc.has_purchase_order else "No" }}</td></tr>
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-red">DOCUMENTS REQUIRED (Open TR)</td></tr>
<tr><td>Commercial Invoice</td><td class="center" style="width:60px;">{{ "Yes" if doc.has_commercial_invoice else "No" }}</td></tr>
<tr><td>BL / AWB</td><td class="center">{{ "Yes" if doc.has_bl_awb else "No" }}</td></tr>
<tr><td>Delivery Note</td><td class="center">{{ "Yes" if doc.has_delivery_note else "No" }}</td></tr>
<tr><td>Bill of Entry</td><td class="center">{{ "Yes" if doc.has_bill_of_entry else "No" }}</td></tr>
</table>
</td>
</tr>
</table>

<div style="border:1px solid #000; padding:8px; margin:15px 0;"><strong>Ref:</strong> {{ doc.name }}</div>

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>{{ ctx.prepared_by_name or "" }}</small></td><td>Authorised-By<br/><small>{{ (ctx.signers.get("Authorised") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>{{ (ctx.signers.get("Approved Level 1") or {}).get("full_name") or "" }}</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>
{% endif %}

{% endif %}

{# ATTACHMENTS #}
{% if doc.payment_references %}
{% for row in doc.payment_references %}
{% if row.reference_doctype and row.reference_name and row.reference_doctype != "Manual" %}
{% set images = get_reference_attachment_images(row.reference_doctype, row.reference_name, max_pages=2) %}
{% if images %}
<div class="att-section">
<div class="header-blue">Attachment: {{ row.reference_doctype }} - {{ row.reference_name }}</div>
{% for img in images %}
<img src="{{ img }}" class="att-img" />
{% endfor %}
</div>
{% endif %}
{% endif %}
{% endfor %}
{% endif %}

</div>
